CVE-2025-24035.script:
# Détection par KB correctif : CVE-2025-24035
# Les KB listés couvrent plusieurs versions de Windows ; une machine n'en
# installe qu'UN (celui de son OS). Donc : protégé dès qu'UN correctif est présent.
$kbCorrecifs = @("KB5053596", "KB5053603", "KB5053638", "KB5053606", "KB5053602", "KB5053598", "KB5053636", "KB5053599", "KB5053618", "KB5053594", "KB5053888", "KB5053995", "KB5053620", "KB5053627", "KB5053886", "KB5053887")
$Session  = New-Object -ComObject Microsoft.Update.Session
$Searcher = $Session.CreateUpdateSearcher()
$Updates  = $Searcher.Search("IsInstalled=1").Updates
$installes = $Updates | ForEach-Object { $_.KBArticleIDs } | ForEach-Object { "KB$_" }
$presents = $kbCorrecifs | Where-Object { $installes -contains $_ }
if ($presents.Count -gt 0) {
    Write-Host "✅ PROTÉGÉ   - CVE-2025-24035 : correctif présent ($($presents -join ', '))" -ForegroundColor Green
} else {
    Write-Host "⚠️  VULNÉRABLE - CVE-2025-24035 : aucun correctif installé (ou CVE non applicable à cet OS)" -ForegroundColor Red
}

